17	import { toast } from "sonner";
18	import { useState } from "react";
19	
20	interface AssetGridProps {
21	  assets: Asset[];
22	  selectedIds: Set<string>;
23	  onSelect: (id: string, event: React.MouseEvent) => void;
24	  onOpenDetail: (id: string) => void;
25	  isLoading: boolean;
26	}
