28	function useNasConfig(): NasConfig | null {
29	  const { data } = useQuery({
30	    queryKey: ["nas-config"],
31	    queryFn: async () => {
32	      const { data, error } = await supabase
33	        .from("admin_config")
34	        .select("key, value")
35	        .in("key", ["NAS_HOST", "NAS_IP", "NAS_SHARE"]);
36	      if (error) throw error;
37	      const map: Record<string, string> = {};
38	      for (const row of data ?? []) map[row.key] = row.value as string;
39	      if (!map.NAS_HOST || !map.NAS_IP || !map.NAS_SHARE) return null;
40	      return { host: map.NAS_HOST, ip: map.NAS_IP, share: map.NAS_SHARE } as NasConfig;
41	    },
42	    staleTime: 60_000,
43	  });
44	  return data ?? null;
45	}
