47	function AssetCard({
48	  asset,
49	  selected,
50	  onSelect,
51	  onOpenDetail,
52	  nasConfig,
53	}: {
54	  asset: Asset;
55	  selected: boolean;
56	  onSelect: (e: React.MouseEvent) => void;
57	  onOpenDetail: () => void;
58	  nasConfig: NasConfig | null;
59	}) {
60	  const [checkingOut, setCheckingOut] = useState(false);
61	
62	  async function handleCheckout() {
63	    setCheckingOut(true);
64	    try {
65	      const { data, error } = await supabase.functions.invoke("helper-api/tokens", {
66	        body: { asset_id: asset.id },
