81	  function handleOpenFolder() {
82	    if (!nasConfig) return;
83	    const paths = getPathDisplayModes(asset.relative_path, nasConfig, null);
84	    const mode = getPreferredPathMode();
85	    const fullPath = mode === "unc_ip" ? paths.uncIp : mode === "synology_drive" ? paths.remote : paths.uncHost;
86	    if (!fullPath) { toast.error("No path available for current path mode"); return; }
