92	
93	  async function handleCopy(text: string, label: string) {
94	    await navigator.clipboard.writeText(text);
95	    toast.success(`Copied ${label}`);
96	  }
97	
98	  return (
99	    <ContextMenu>
100	      <ContextMenuTrigger asChild>
101	        <button
102	          onClick={onSelect}
103	          className={cn(
104	            "group relative flex flex-col overflow-hidden rounded-lg border bg-card transition-all hover:border-primary/50 text-left",
105	            selected ? "border-primary ring-1 ring-primary" : "border-border",
