122	
123	            {/* File type badge */}
124	            <Badge
125	              variant="secondary"
126	              className="absolute bottom-2 right-2 text-[10px] px-1.5 py-0 uppercase"
127	            >
128	              {asset.file_type}
129	            </Badge>
130	
131	            {/* Licensed/Generic badge */}
132	            <Badge
133	              variant={asset.is_licensed ? "default" : "secondary"}
134	              className="absolute top-2 left-2 text-[10px] px-1.5 py-0"
135	            >
136	              {asset.is_licensed ? "Licensed" : "Generic"}
137	            </Badge>
138	
139	            {selected && <div className="absolute inset-0 bg-primary/10" />}
140	          </div>
141	
142	          {/* Info */}
143	          <div className="flex flex-col gap-1 p-2.5">
