147	            {asset.cover_description && (
148	              <span className="truncate text-[11px] text-muted-foreground italic" title={asset.cover_description}>
149	                {asset.cover_description}
150	              </span>
151	            )}
152	            {asset.sku && (
153	              <span className="truncate text-[11px] font-mono text-muted-foreground" title={asset.sku}>
154	                {asset.sku}
155	              </span>
156	            )}
157	            <div className="flex items-center gap-1.5">
158	              {asset.workflow_status && asset.workflow_status !== "other" && (
159	                <span className="rounded bg-tag px-1.5 py-0.5 text-[10px] text-tag-foreground capitalize">
160	                  {asset.workflow_status.replace(/_/g, " ")}
161	                </span>
162	              )}
163	            </div>
164	          </div>
165	        </button>
166	      </ContextMenuTrigger>
167	
168	      <ContextMenuContent className="w-52">
169	        <ContextMenuItem onClick={handleCheckout} disabled={checkingOut}>
170	          {checkingOut
171	            ? <Loader2 className="h-3.5 w-3.5 mr-2 animate-spin" />
172	            : <Download className="h-3.5 w-3.5 mr-2" />}
173	          Check Out &amp; Open
174	        </ContextMenuItem>
175	        {nasConfig && (
176	          <ContextMenuItem onClick={handleOpenFolder}>
177	            <FolderOpen className="h-3.5 w-3.5 mr-2" />
178	            Open Containing Folder
179	          </ContextMenuItem>
180	        )}
181	        <ContextMenuSeparator />
182	        <ContextMenuItem onClick={() => handleCopy(asset.relative_path, "relative path")}>
183	          <Copy className="h-3.5 w-3.5 mr-2" />
184	          Copy Relative Path
185	        </ContextMenuItem>
186	        {nasConfig && (() => {
187	          const paths = getPathDisplayModes(asset.relative_path, nasConfig, null);
188	          return (
189	            <ContextMenuItem onClick={() => handleCopy(paths.uncHost, "UNC path")}>
190	              <Copy className="h-3.5 w-3.5 mr-2" />
191	              Copy UNC Path
192	            </ContextMenuItem>
193	          );
194	        })()}
195	        <ContextMenuSeparator />
196	        <ContextMenuItem onClick={onOpenDetail}>
197	          <PanelRight className="h-3.5 w-3.5 mr-2" />
198	          View Details
199	        </ContextMenuItem>
200	      </ContextMenuContent>
201	    </ContextMenu>
202	  );
203	}
204	
205	export default function AssetGrid({ assets, selectedIds, onSelect, onOpenDetail, isLoading }: AssetGridProps) {
206	  const nasConfig = useNasConfig();
207	
208	  if (isLoading && assets.length === 0) {
209	    return (
210	      <div className="grid grid-cols-[repeat(auto-fill,minmax(200px,1fr))] gap-3 p-4">
211	        {Array.from({ length: 12 }).map((_, i) => (
212	          <div key={i} className="flex flex-col overflow-hidden rounded-lg border border-border bg-card animate-pulse">
213	            <div className="aspect-[4/3] bg-muted/30" />
214	            <div className="p-2.5 space-y-2">
215	              <div className="h-4 w-3/4 rounded bg-muted/30" />
216	              <div className="h-3 w-1/2 rounded bg-muted/20" />
217	            </div>
218	          </div>
219	        ))}
220	      </div>
221	    );
222	  }
223	
224	  if (assets.length === 0) {
225	    return (
226	      <div className="flex flex-col items-center justify-center py-24 text-center">
227	        <ImageOff className="h-12 w-12 text-muted-foreground/30 mb-4" />
228	        <p className="text-muted-foreground">No assets found</p>
229	      </div>
230	    );
231	  }
232	
233	  return (
234	    <div className="grid grid-cols-[repeat(auto-fill,minmax(200px,1fr))] gap-3 p-4">
235	      {assets.map((asset) => (
236	        <AssetCard
237	          key={asset.id}
238	          asset={asset}
239	          selected={selectedIds.has(asset.id)}
240	          onSelect={(e) => onSelect(asset.id, e)}
241	          onOpenDetail={() => onOpenDetail(asset.id)}
242	          nasConfig={nasConfig}
243	        />
244	      ))}
245	    </div>
246	  );
247	}
